// Fusionar todos los datos recopilados en un objeto unificado
const input    = $('Validar Formato TXN').first().json;
const txn      = $('Obtener Transacción').first().json || {};
const logsData = $('Obtener Logs').first().json || {};
const policies = $('Buscar Políticas').first().json || {};
const cases    = $('Buscar Casos Similares').first().json || {};
const sla      = $('Verificar SLA').first().json || {};

// Merchant: datos crudos de FastAPI + flags evaluados en n8n
let merchant = {};
try {
  merchant = {
    ...$('Riesgo del Comercio').first().json,
    ...$('Evaluar Riesgo Comercio').first().json,
  };
} catch (e) { merchant = { error: e.message }; }

// Cliente: datos crudos de FastAPI + flags evaluados en n8n
let client = {};
try {
  client = {
    ...$('Historial del Cliente').first().json,
    ...$('Evaluar Historial Cliente').first().json,
  };
} catch (e) { client = { error: e.message }; }

const slaStatus = sla.within_sla != null
  ? (sla.within_sla
    ? `dentro de SLA (${sla.days_elapsed}d / ${sla.sla_limit_days}d)`
    : `FUERA de SLA (${sla.days_elapsed}d / ${sla.sla_limit_days}d)`)
  : 'SLA no calculado';

const agentAnalysis = [
  `Caso ${input.transaction_id}: ${txn.merchant || 'N/A'}, USD ${txn.amount_usd || 0},`,
  `canal ${txn.channel || 'N/A'}, país ${txn.country || 'N/A'}, score fraude ${txn.fraud_score ?? 'N/A'}.`,
  `Motivo: ${input.motivo || 'no especificado'}.`,
  `SLA: ${slaStatus}.`,
  `Cliente VIP: ${input.cliente_vip ? 'sí' : 'no'}.`,
  `Políticas encontradas: ${(policies.results || []).length}.`,
  `Casos similares: ${(cases.results || []).length}.`,
].join(' ');

return [{
  json: {
    transaction_id:  input.transaction_id,
    motivo:          input.motivo,
    cliente_vip:     input.cliente_vip,
    tx_data:         txn,
    logs:            logsData.logs || [],
    policies:        policies.results || [],
    similar_cases:   cases.results || [],
    merchant_risk:   merchant,
    client_history:  client,
    sla:             sla,
    agent_analysis:  agentAnalysis,
  }
}];

// Construir el payload exacto que espera POST /api/reports/html (ReportRequest)
const ctx        = $('Compilar Contexto').first().json;
const resolution = $('Sintetizar Resolución').first().json;
const judge      = $input.first().json.judge_evaluation || {
  overall_score: 5.0,
  criteria: {},
  approved: false,
  strengths: [],
  weaknesses: ['Judge evaluation unavailable'],
};

return [{
  json: {
    transaction:         ctx.tx_data,
    resolution:          resolution,
    judge_evaluation:    judge,
    agent_analysis:      ctx.agent_analysis,
    merchant_risk:       ctx.merchant_risk,
    client_profile:      ctx.client_history,
    logs:                ctx.logs,
    policies_evaluated:  ctx.policies,
    similar_cases:       ctx.similar_cases,
    hitl_decision:       null,
    cache_hit:           false,
    guardrail_warnings:  resolution.guardrail_warnings || [],
    motivo:              ctx.motivo || '',
    cliente_vip:         ctx.cliente_vip || false,
  }
}];

// Compatible con resume via webhook y form submission nativo
const resume     = $input.first().json;
const ctx        = $('Compilar Contexto').first().json;
const resolution = $('Sintetizar Resoluci\u00f3n').first().json;
const judge      = $('Extraer Evaluaci\u00f3n \u2014 Juez').first().json.judge_evaluation;

// Form fields: 'Decisi\u00f3n' / 'Notas del Analista'; webhook: 'decision' / 'notes'
const rawDecision = resume['Decisi\u00f3n'] || resume.decision || 'APPROVE';
const rawNotes    = resume['Notas del Analista'] || resume.notes || '';

const hitlDecision = {
  analyst_decision: rawDecision.toUpperCase(),
  analyst_notes:    rawNotes,
  final_outcome:    rawDecision.toUpperCase() === 'REJECT' ? 'DENIED' : 'APPROVED',
  timestamp:        new Date().toISOString(),
};

return [{
  json: {
    transaction:         ctx.tx_data,
    resolution:          resolution,
    judge_evaluation:    judge,
    agent_analysis:      ctx.agent_analysis,
    merchant_risk:       ctx.merchant_risk,
    client_profile:      ctx.client_history,
    logs:                ctx.logs,
    policies_evaluated:  ctx.policies,
    similar_cases:       ctx.similar_cases,
    hitl_decision:       hitlDecision,
    cache_hit:           false,
    guardrail_warnings:  resolution.guardrail_warnings || [],
    motivo:              ctx.motivo || '',
    cliente_vip:         ctx.cliente_vip || false,
    _feedback_payload: {
      transaction_id:    ctx.transaction_id,
      analyst_decision:  hitlDecision.analyst_decision,
      analyst_notes:     hitlDecision.analyst_notes,
      final_outcome:     hitlDecision.final_outcome,
      judge_score:       judge.overall_score ?? 0,
    }
  }
}];

// Verificar Guardrails post-LLM — visibilidad en el canvas
const resolution = $input.first().json;
const warnings = resolution.guardrail_warnings || [];
const verdicts = resolution.policy_verdicts || [];

const hasBLOCKER = verdicts.some(v => v.verdict === 'BLOCKER');
const isAPPROVE = resolution.recommended_action === 'APPROVE';
const compExcesiva = (resolution.compensation_amount_usd || 0) > (resolution.transaction_amount_usd || 99999) * 1.1;
const failCount = verdicts.filter(v => ['FAIL','BLOCKER'].includes(v.verdict)).length;
const overConfident = (resolution.confidence || 0) > 0.95 && failCount >= 2;

const guardrailStatus = {
  approve_with_blocker: isAPPROVE && hasBLOCKER,
  compensation_excesiva: compExcesiva,
  overconfident: overConfident,
  total_warnings: warnings.length,
  warnings: warnings,
  status: warnings.length > 0 ? 'GUARDRAILS ACTIVADOS' : 'Sin alertas'
};

return [{ json: { ...resolution, _guardrail_check: guardrailStatus } }];
